        this.seektimeupdate = function () {
            var currentTime = video.currentTime;
            var duration = video.duration;
            $('.hp_range').stop(true, true).animate({ 'width': (currentTime + .25) / duration * 100 + '%' }, 250, 'linear');

            // seekslider.value = nt;
            var curmins = Math.floor(video.currentTime / 60);
            var cursecs = Math.floor(video.currentTime - curmins * 60);
            var durmins = 0;
            var dursecs = 0;
            if (video.duration > 0) {
                durmins = Math.floor(video.duration / 60);;
                dursecs = Math.floor(video.duration - durmins * 60);
            }
            if (cursecs < 10) { cursecs = "0" + cursecs; }
            if (dursecs < 10) { dursecs = "0" + dursecs; }
            if (curmins < 10) { curmins = "0" + curmins; }
            if (durmins < 10) { durmins = "0" + durmins; }

            $('#pano_video_time').text(curmins + ":" + cursecs + " / " + durmins + ":" + dursecs);
        };

        this.updateVideoProgress = function (x, vol) {
            var volume = $('.hp_slide');
            var percentage;
            //if only volume have specificed
            //then direct update volume
            if (vol) {
                percentage = vol * 100;
            } else {
                var position = x - volume.offset().left;
                percentage = 100 * position / volume.width();
            }

            if (percentage > 100) {
                percentage = 100;
            }
            if (percentage < 0) {
                percentage = 0;
            }

            $('.hp_range').stop(true, true).animate({ 'width': percentage + '%' }, 250, 'linear');
            video.currentTime = (percentage / 100) * video.duration;
        };

        this.updateVolume = function (x, vol) {
            var volume = $('.volume');
            var percentage;

            if (vol) {
                percentage = vol * 100;
            } else {
                var position = x - volume.offset().left;
                percentage = 100 * position / volume.width();
            }

            if (percentage > 100) {
                percentage = 100;
            }
            if (percentage < 0) {
                percentage = 0;
            }

            $('.volumeBar').css('width', percentage + '%');
            video.volume = percentage / 100;

            if (video.volume == 0) {
                $('.sound').removeClass('sound2').addClass('muted');
            } else if (video.volume > 0.5) {
                $('.sound').removeClass('muted').addClass('sound2');
            } else {
                $('.sound').removeClass('muted').removeClass('sound2');
            }

        };

