            var big_screen = this.options.bigScreen ? "<div class='pano_btn pano_bigscreen' title='" + getTranslation("player_bigger_screen", this.options.language) + "'><i class='fa fa-window-maximize'></i></div>" : "";
            var play = "<div class='pano_btn pano_play' title='" + getTranslation("vir_web_vv_autorotate_on", this.options.language) + "'><i class='fa fa-rotate-left'></i></div>";
            var pause = "<div class='pano_btn pano_pause' style='display: none' title='" + getTranslation("vir_web_vv_autorotate_off", this.options.language) + "'><i class='fa fa-pause'></i></div>";
            var zoomin = "<div class='pano_btn pano_zoomin' title='" + getTranslation("vir_web_vv_zoom_in", this.options.language) + "'><i class='fa fa-search-plus'></i></div>";
            var zoomout = "<div class='pano_btn pano_zoomout' title='" + getTranslation("vir_web_vv_zoom_out", this.options.language) + "'><i class='fa fa-search-minus'></i></div>";


            var deviceOrient = "<div class='pano_btn pano_orientation'><i class='fa fa-compass'></i></div>";
            var vr = "<div class='pano_btn pano_vr' title='" + getTranslation("vir_web_vv_mode_vr") + "'><i class='fa fa-simplybuilt'></i></div>";


            var leftMenu = "<div class='pano_left_menu'>" + full_screen + big_screen + play + pause + zoomin + zoomout + "</div>";
            $("#" + this.options.container).append(leftMenu);

            if (this.options.video && this.options.edit){
                var snapshot = "<div class='pano_btn pano_snapshot' title='" + getTranslation("player_save_snapshot") + "'><i class='fa fa-camera-retro'></i></div>";
                $('.pano_left_menu').append(snapshot);
                // this.takeSnapshot();
            }

            this.fullScreen2();
            this.bigScreen();
            this.zoominF();
            this.zoomoutF();
            this.autorotateStart();
            this.autorotateStop();
            this.deviceOrientation();

            //check if device has orientation
            function deviceOrientationTest(e) {
                window.removeEventListener('deviceorientation', deviceOrientationTest);
                if (e && e.alpha !== null && e.beta !== null && e.gamma !== null) {
                    gyroPresent = true;
                    $('.pano_left_menu').append(deviceOrient);
                } else {
                    gyroPresent = false;
                }
            }
            if (window.DeviceOrientationEvent) {
                window.addEventListener('deviceorientation', deviceOrientationTest);
            } else {
                gyroPresent = false;
            }

            core.isWebVr(function(disp) {
                if(disp){
                  $('.pano_left_menu').append(vr);
                  that.vrMode();
                }
            });

